import chalk from 'chalk';

import {
  ExitCode,
  errorCodeToExitCode,
  type CliErrorDetails,
  type CliErrorResponse,
  type CliResponse,
  type CliSuccessResponse,
  type ErrorCode,
} from './types';

import type { JsonStringifyValue } from '@/shared/neverthrow/json/types';
import type { GlobalFlags } from '@/types';
import type { BaseError, Err } from '@agentcash/neverthrow/types';

/**
 * Create a success response
 */
export function successResponse(
  data: JsonStringifyValue,
  metadata?: JsonStringifyValue
): CliSuccessResponse {
  return {
    success: true,
    data,
    metadata,
  };
}

/**
 * Create an error response
 */
export function errorResponse(error: CliErrorDetails): CliErrorResponse {
  return {
    success: false,
    error,
  };
}

/**
 * Convert a neverthrow error to a CLI error response
 */
export function fromNeverthrowError(
  err: Err<unknown, BaseError<string>>,
  codeOverride?: ErrorCode
): CliErrorResponse {
  const { error } = err;
  const code = codeOverride ?? mapCauseToErrorCode(error.cause);

  return errorResponse({
    code,
    message: error.message,
    surface: error.surface,
    cause: error.cause,
  });
}

/**
 * Map error cause to error code
 */
function mapCauseToErrorCode(cause: string): ErrorCode {
  switch (cause) {
    case 'network':
      return 'NETWORK_ERROR';
    case 'http':
      return 'HTTP_ERROR';
    case 'parse':
      return 'PARSE_ERROR';
    case 'insufficient_balance':
      return 'INSUFFICIENT_BALANCE';
    case 'payment_failed':
    case 'payment_already_attempted':
      return 'PAYMENT_FAILED';
    case 'invalid_input':
    case 'validation':
      return 'INVALID_INPUT';
    case 'wallet':
    case 'file_not_readable':
      return 'WALLET_ERROR';
    default:
      return 'GENERAL_ERROR';
  }
}

const MAX_ERROR_MESSAGE_LENGTH = 200;

/**
 * Format error fields for output.
 * Truncates the message unless verbose. Verbose also includes raw details.
 */
function formatError(error: CliErrorDetails, verbose: boolean) {
  const statusCode =
    error.details &&
    typeof error.details === 'object' &&
    'statusCode' in error.details &&
    typeof error.details.statusCode === 'number'
      ? error.details.statusCode
      : undefined;
  const [message, truncated] = verbose
    ? [error.message, false]
    : error.message.length > MAX_ERROR_MESSAGE_LENGTH
      ? [error.message.slice(0, MAX_ERROR_MESSAGE_LENGTH) + '...', true]
      : [error.message, false];
  return { statusCode, message, truncated };
}

/**
 * Build a compact error object for JSON output (no redundant body).
 * Verbose mode includes the full details.
 */
function buildJsonError(error: CliErrorDetails, verbose: boolean) {
  const { statusCode, message, truncated } = formatError(error, verbose);
  return {
    ...error,
    message,
    statusCode,
    ...(truncated ? { hint: 'Use --verbose for the full error.' } : {}),
  };
}

/**
 * Format response as JSON string
 */
function formatJson(response: CliResponse, verbose: boolean): string {
  if (response.success) return JSON.stringify(response, null, 2);

  return JSON.stringify(
    { success: false, error: buildJsonError(response.error, verbose) },
    null,
    2
  );
}

/**
 * Format response as pretty output for TTY
 */
function formatPretty(response: CliResponse, verbose: boolean): string {
  if (response.success) {
    const lines: string[] = [];

    // Data
    if (typeof response.data === 'string') {
      lines.push(response.data);
    } else {
      lines.push(JSON.stringify(response.data, null, 2));
    }

    // Metadata
    if (response.metadata) {
      lines.push('');
      lines.push(JSON.stringify(response.metadata, null, 2));
    }

    return lines.join('\n');
  }

  const { error } = response;
  const { statusCode, message, truncated } = formatError(error, verbose);

  const prefix = statusCode != null ? `Error (${statusCode})` : 'Error';
  const lines = [
    chalk.red(`${prefix}: ${message}`),
    chalk.dim(`Code: ${error.code}`),
  ];

  if (error.surface) lines.push(chalk.dim(`Surface: ${error.surface}`));
  if (error.cause) lines.push(chalk.dim(`Cause: ${error.cause}`));

  if (truncated) {
    lines.push(chalk.dim('Use --verbose for the full error.'));
  }

  if (error.details) {
    lines.push(chalk.dim(`Details: ${JSON.stringify(error.details, null, 2)}`));
  }

  return lines.join('\n');
}

/**
 * Output a response to stdout and exit with appropriate code
 */
export function outputAndExit(
  response: CliResponse,
  flags: GlobalFlags
): never {
  const verbose = flags.verbose ?? false;

  if (!flags.quiet) {
    console.log(
      flags.format === 'json'
        ? formatJson(response, verbose)
        : formatPretty(response, verbose)
    );
  }

  const exitCode = response.success
    ? ExitCode.Success
    : errorCodeToExitCode[response.error.code];

  process.exit(exitCode);
}
